import { __decorate } from "tslib";
import __NG_CLI_RESOURCE__0 from "./icon.scss?ngResource";
import { Component, Input } from '@angular/core';
let IconComponent = class IconComponent {
    constructor() {
        this.size = 'md';
        this.color = 'default';
        this.background = 'default';
    }
    static { this.propDecorators = {
        icon: [{ type: Input }],
        size: [{ type: Input }],
        alt: [{ type: Input }],
        color: [{ type: Input }],
        background: [{ type: Input }]
    }; }
};
IconComponent = __decorate([
    Component({
        selector: 'app-icon',
        standalone: true,
        template: `
    <img
      *ngIf="icon"
      class="icon"
      [class]="size + ' ' + color + background" 
      [src]="'assets/icons/' + icon + '.svg'"
      [alt]="alt || icon"

    />
  `,
        styles: [__NG_CLI_RESOURCE__0]
    })
], IconComponent);
export { IconComponent };
